// Verify platform-admin session and validate doctor fields for an existing clinic.
const raw = $input.first().json;
const body = raw.body || raw;
const headers = raw.headers || {};
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';
const authHeader = String(header('authorization') || '');
const accessToken = authHeader.replace(/^Bearer\s+/i, '').trim();
const supabaseUrl = String($env.SUPABASE_URL || '').replace(/\/+$/, '');
const anonKey = String($env.SUPABASE_ANON_KEY || '');
const errors = [];

const clean = (value, max = 1000) => String(value || '').trim().slice(0, max);
const normalizeUsername = value => clean(value, 80).toLowerCase();
const usernameToInternalEmail = username => normalizeUsername(username) + '@auth.vaitalcare.local';
const isUrl = value => /^https:\/\//i.test(value);

const clinicId = clean(body.clinic_id, 80);
const doctorName = clean(body.doctor_name, 150);
const doctorQualification = clean(body.doctor_qualification, 200) || null;
const doctorExpertise = clean(body.doctor_expertise, 500);
const doctorRegistration = clean(body.doctor_registration_number, 120);
const doctorPhone = clean(body.doctor_phone, 20).replace(/\s+/g, '') || null;
const doctorSignatureUrl = clean(body.doctor_signature_url, 1000) || null;
const loginUsername = normalizeUsername(body.login_username);
const password = String(body.password || '');
const sendWhatsapp = ['true', '1', 'yes', 'on'].includes(String(body.send_whatsapp || '').toLowerCase());

if (!supabaseUrl || !anonKey) errors.push('SUPABASE_URL and SUPABASE_ANON_KEY are required');
if (!accessToken) errors.push('authorization: platform admin session token is required');
if (!clinicId || !/^[0-9a-f-]{36}$/i.test(clinicId)) errors.push('clinic_id: valid UUID is required');
if (!doctorName || doctorName.length < 2) errors.push('doctor_name: required, minimum 2 characters');
if (doctorQualification && doctorQualification.length < 2) errors.push('doctor_qualification: minimum 2 characters when provided');
if (!doctorExpertise || doctorExpertise.length < 2) errors.push('doctor_expertise: required, minimum 2 characters');
if (!doctorRegistration || doctorRegistration.length < 2) errors.push('doctor_registration_number: required, minimum 2 characters');
if (doctorPhone && !/^\+?[1-9]\d{6,14}$/.test(doctorPhone)) errors.push('doctor_phone: must be a valid phone number');
if (doctorSignatureUrl && !isUrl(doctorSignatureUrl)) errors.push('doctor_signature_url: must be an HTTPS URL');
if (!/^[a-z0-9._-]{3,80}$/.test(loginUsername)) errors.push('login_username: required, use lowercase letters, numbers, dot, underscore, or hyphen');
if (!password || password.length < 8) errors.push('password: required, minimum 8 characters');

if (errors.length > 0) return [{ json: { _valid: false, _errors: errors } }];

async function httpJson(method, url, { headers = {}, body } = {}) {
  const opts = { method, url, headers, json: true, returnFullResponse: true, ignoreHttpStatusErrors: true };
  if (body !== undefined) opts.body = body;
  return this.helpers.httpRequest(opts);
}

let adminUserId = '';
try {
  const userRes = await httpJson.call(this, 'GET', supabaseUrl + '/auth/v1/user', {
    headers: { apikey: anonKey, Authorization: 'Bearer ' + accessToken },
  });
  adminUserId = String((userRes.body || {}).id || '');
  if (!adminUserId) errors.push('authorization: invalid or expired session');

  if (!errors.length) {
    const adminRes = await httpJson.call(this, 'POST', supabaseUrl + '/rest/v1/rpc/current_user_is_platform_admin', {
      headers: { apikey: anonKey, Authorization: 'Bearer ' + accessToken, 'Content-Type': 'application/json' },
      body: {},
    });
    if (adminRes.statusCode >= 400 || adminRes.body !== true) {
      errors.push('authorization: caller is not a platform administrator');
    }
  }
} catch (err) {
  errors.push('authorization: could not verify admin session — ' + String(err.message || err));
}

if (errors.length > 0) return [{ json: { _valid: false, _errors: errors } }];

return [{
  json: {
    _valid: true,
    _errors: [],
    admin_user_id: adminUserId,
    clinic_id: clinicId,
    doctor_name: doctorName,
    doctor_qualification: doctorQualification,
    doctor_expertise: doctorExpertise,
    doctor_registration_number: doctorRegistration,
    doctor_phone: doctorPhone,
    doctor_signature_url: doctorSignatureUrl,
    login_username: loginUsername,
    auth_email: usernameToInternalEmail(loginUsername),
    _password: password,
    send_whatsapp: sendWhatsapp,
  }
}];

// Create Supabase Auth user for the new test doctor.
try {
  const supabaseUrl = String($env.SUPABASE_URL || '').replace(/\/+$/, '');
  const serviceRoleKey = String($env.SUPABASE_SERVICE_ROLE_KEY || '');
  if (!supabaseUrl || !serviceRoleKey) {
    return [{ json: { _auth_failed: true, _errors: ['SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are required for doctor account creation'] } }];
  }

  async function httpJson(method, url, { headers = {}, body } = {}) {
    const opts = { method, url, headers, json: true, returnFullResponse: true, ignoreHttpStatusErrors: true };
    if (body !== undefined) opts.body = body;
    return this.helpers.httpRequest(opts);
  }

  const data = $input.first().json;
  const password = data._password;
  if (!password) {
    return [{ json: { _auth_failed: true, _errors: ['Password missing for ' + data.login_username] } }];
  }

  const payload = {
    email: data.auth_email,
    password,
    email_confirm: true,
    user_metadata: {
      login_username: data.login_username,
      role: 'doctor',
      doctor_name: data.doctor_name,
      admin_provisioned: true,
    },
  };

  const response = await httpJson.call(this, 'POST', supabaseUrl + '/auth/v1/admin/users', {
    headers: {
      apikey: serviceRoleKey,
      Authorization: 'Bearer ' + serviceRoleKey,
      'Content-Type': 'application/json',
    },
    body: payload,
  });

  let authUser = response.body || {};
  const duplicate = response.statusCode === 422 || /already|registered|exists/i.test(JSON.stringify(authUser));
  if (response.statusCode >= 400 && !duplicate) {
    const detail = authUser.msg || authUser.message || authUser.error_description || JSON.stringify(authUser).slice(0, 240);
    return [{ json: { _auth_failed: true, _errors: ['Could not create dashboard account for username ' + data.login_username + ': ' + detail] } }];
  }

  if (duplicate) {
    return [{ json: { _auth_failed: true, _errors: ['login_username: already in use'] } }];
  }

  if (!authUser.id) {
    return [{ json: { _auth_failed: true, _errors: ['Dashboard account created but auth user id missing for ' + data.login_username] } }];
  }

  const { _password, ...safeData } = data;
  return [{ json: { ...safeData, auth_user_id: authUser.id } }];
} catch (err) {
  return [{ json: { _auth_failed: true, _errors: [String(err.message || err)] } }];
}

const row = $input.first().json;
const provision = row.result || {};
const prev = $('Create Doctor Auth User').first().json;
return [{
  json: {
    ...prev,
    provision,
    boarding_id: provision.boarding_id,
    doctor_profile_id: provision.doctor_profile_id,
  }
}];

const row = $('Merge Provision Result').first().json;
const boarding = $input.first().json || {};
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const scheduledDate = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const contentSid = $env.TWILIO_CONTENT_HOSPITAL_ONBOARDING || '';

function toE164(raw) {
  const p = String(raw || '').trim().replace(/\s+/g, '');
  if (!p) return '';
  if (/^\+[1-9]\d{6,14}$/.test(p)) return p;
  if (/^[0-9]{10}$/.test(p)) return '+91' + p;
  if (/^[1-9]\d{6,14}$/.test(p)) return '+' + p;
  return '';
}

const hospital = String(boarding.hospital_name || '').trim();
const facility = String(boarding.facility_type || '').trim();
const doctor = String(row.doctor_name || '').trim();
const city = String(boarding.city || '').trim();
const contentVars = JSON.stringify({ '1': hospital, '2': facility, '3': doctor, '4': city });
const messageBody = 'Hi ' + hospital + ', your onboarding for ' + facility + ' is complete. We have registered ' + doctor + ' as a dashboard user and ' + city + ' as the facility location.';

const targets = [
  { role: 'clinic', phone: toE164(boarding.contact_phone) },
  { role: 'doctor', phone: toE164(boarding.doctor_phone || row.doctor_phone) },
];
const seen = new Set();
const out = [];
for (const t of targets) {
  if (!t.phone || seen.has(t.phone)) continue;
  seen.add(t.phone);
  out.push({
    json: {
      _skip: false,
      _recipient_role: t.role,
      _phone: t.phone,
      _to_phone: 'whatsapp:' + t.phone,
      _clinic_id: row.clinic_id,
      _hospital_name: hospital,
      _doctor_name: doctor,
      _message_type: 'hospital_onboarding',
      _scheduled_date: scheduledDate,
      _content_sid: contentSid,
      _content_variables: contentVars,
      _message_body: messageBody,
      provision: row.provision,
      login_username: row.login_username,
      doctor_name: row.doctor_name,
    },
  });
}
if (out.length === 0) {
  return [{ json: { _skip_wa: true, provision: row.provision, login_username: row.login_username, doctor_name: row.doctor_name, clinic_id: row.clinic_id } }];
}
return out;
